function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;

    // Precompute teleportList
    const teleportList = new Array(m).fill().map(() => new Array(n).fill().map(() => []));
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const val = grid[i][j];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= val) {
                        teleportList[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    // Initialize distance array
    const dist = new Array(m).fill().map(() => new Array(n).fill().map(() => new Array(k + 1).fill(Infinity)));
    dist[0][0][0] = 0;

    // Priority queue: min-heap
    class PriorityQueue {
        constructor() {
            this.heap = [];
        }
        push(value) {
            this.heap.push(value);
            this.bubbleUp(this.heap.length - 1);
        }
        pop() {
            if (this.heap.length === 0) return null;
            const min = this.heap[0];
            this.heap[0] = this.heap[this.heap.length - 1];
            this.heap.pop();
            this.bubbleDown(0);
            return min;
        }
        bubbleUp(index) {
            while (index > 0) {
                const parentIndex = Math.floor((index - 1) / 2);
                if (this.heap[index][0] < this.heap[parentIndex][0]) {
                    [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                    index = parentIndex;
                } else {
                    break;
                }
            }
        }
        bubbleDown(index) {
            while (index < this.heap.length) {
                const leftIndex = 2 * index + 1;
                const rightIndex = 2 * index + 2;
                let smallestIndex = index;
                if (leftIndex < this.heap.length && this.heap[leftIndex][0] < this.heap[smallestIndex][0]) {
                    smallestIndex = leftIndex;
                }
                if (rightIndex < this.heap.length && this.heap[rightIndex][0] < this.heap[smallestIndex][0]) {
                    smallestIndex = rightIndex;
                }
                if (smallestIndex !== index) {
                    [this.heap[index], this.heap[smallestIndex]] = [this.heap[smallestIndex], this.heap[index]];
                    index = smallestIndex;
                } else {
                    break;
                }
            }
        }
        isEmpty() {
            return this.heap.length === 0;
        }
    }

    const pq = new PriorityQueue();
    pq.push([0, 0, 0, 0]);

    while (!pq.isEmpty()) {
        const [cost, i, j, t] = pq.pop();
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > dist[i][j][t]) continue;

        // Regular moves: right and down
        if (j + 1 < n) {
            const new_i = i;
            const new_j = j + 1;
            const new_cost = cost + grid[new_i][new_j];
            if (new_cost < dist[new_i][new_j][t]) {
                dist[new_i][new_j][t] = new_cost;
                pq.push([new_cost, new_i, new_j, t]);
            }
        }
        if (i + 1 < m) {
            const new_i = i + 1;
            const new_j = j;
            const new_cost = cost + grid[new_i][new_j];
            if (new_cost < dist[new_i][new_j][t]) {
                dist[new_i][new_j][t] = new_cost;
                pq.push([new_cost, new_i, new_j, t]);
            }
        }

        // Teleportation
        if (t < k) {
            for (const [x, y] of teleportList[i][j]) {
                const new_t = t + 1;
                if (dist[x][y][new_t] > cost) {
                    dist[x][y][new_t] = cost;
                    pq.push([cost, x, y, new_t]);
                }
            }
        }
    }

    return -1;
}
