    const m = grid.length;
    const n = grid[0].length;

    // Precompute teleport_map
    const teleport_map = Array(m).fill().map(() => Array(n).fill().map(() => []));
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const val = grid[i][j];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= val) {
                        teleport_map[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    // Dijkstra's algorithm
    const dist = Array(m).fill().map(() => Array(n).fill().map(() => Array(k + 1).fill(Infinity)));
    dist[0][0][0] = 0;

    // Priority queue: min-heap
    const pq = [];
    pq.push([0, 0, 0, 0]);

    function push(heap, value) {
        heap.push(value);
        let i = heap.length - 1;
        while (i > 0) {
            const parent = Math.floor((i - 1) / 2);
            if (heap[i][0] >= heap[parent][0]) {
                [heap[i], heap[parent]] = [heap[parent], heap[i]];
                i = parent;
            } else {
                break;
            }
        }
    }

    function pop(heap) {
        if (heap.length === 0) return null;
        const val = heap[0];
        heap[0] = heap[heap.length - 1];
        heap.pop();
        let i = 0;
        while (i < heap.length) {
            const left = 2 * i + 1;
            const right = 2 * i + 2;
            let smallest = i;
            if (left < heap.length && heap[left][0] < heap[smallest][0]) {
                smallest = left;
            }
            if (right < heap.length && heap[right][0] < heap[smallest][0]) {
                smallest = right;
            }
            if (smallest !== i) {
                [heap[i], heap[smallest]] = [heap[smallest], heap[i]];
                i = smallest;
            } else {
                break;
            }
        }
        return val;
    }

    while (pq.length > 0) {
        const [cost, i, j, t] = pop(pq);
        if (i === m - 1 && j === n - 1) return cost;
        if (cost > dist[i][j][t]) continue;

        // Move right
        if (j + 1 < n) {
            const new_cost = cost + grid[i][j + 1];
            if (new_cost < dist[i][j + 1][t]) {
                dist[i][j + 1][t] = new_cost;
                push(pq, [new_cost, i, j + 1, t]);
            }
        }

        // Move down
        if (i + 1 < m) {
            const new_cost = cost + grid[i + 1][j];
            if (new_cost < dist[i + 1][j][t]) {
                dist[i + 1][j][t] = new_cost;
                push(pq, [new_cost, i + 1, j, t]);
